import 'package:flutter_fractals/core/modules/base_classes/raymarch_3d_module_base.dart';
import 'package:flutter_fractals/core/modules/base_classes/shader_params.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  test('module base contracts keep their documented defaults', () {
    expect(_Attractor().defaultIterations, 100000);
    expect(_Attractor().defaultStepSize, 0.01);

    expect(_Cellular().defaultGenerations, 100);

    final escapeTime = _EscapeTime();
    expect(escapeTime.defaultPower, 2.0);
    expect(escapeTime.defaultBailout, 2.0);
    expect(escapeTime.defaultIterations, 500);
    expect(escapeTime.deepZoom, DeepZoomStrategy.none);

    expect(_IFS().defaultIterations, 50000);
    expect(_LSystem().defaultDepth, 6);

    final raymarched3D = _Raymarched3D();
    expect(raymarched3D.defaultPower, 8.0);
    expect(raymarched3D.defaultSteps, 120);
    expect(raymarched3D.defaultIterations, 10);
  });

  test('ShaderParams exposes backend-independent uniform setters', () {
    final params = _RecordingShaderParams();

    params
      ..setFloat('power', 2.5)
      ..setInt('iterations', 80)
      ..setBool('enabled', true)
      ..setVec2('center', -0.5, 0.25)
      ..setVec3('camera', 1, 2, 3);

    expect(params.calls, <String>[
      'float:power=2.5',
      'int:iterations=80',
      'bool:enabled=true',
      'vec2:center=-0.5,0.25',
      'vec3:camera=1.0,2.0,3.0',
    ]);
  });
}

