// Shared contract for pipeline-emitted fractal module base classes.
import 'package:meta/meta.dart';

import '../shader_contracts/shader_params.dart';

@immutable
abstract class PipelineModuleBase {
  final String id;
  final String shader;

  const PipelineModuleBase({
    required this.id,
    required this.shader,
  });

  Object get metadata;
  List<Object> get presets;
  List<Object> get variants;

  void configureShader(ShaderParams p);
}

