// Base class for complex-plane escape-time fractals (Mandelbrot family, Julia, etc.).
import '../pipeline_contracts/pipeline_module_base.dart';
import '../shader_contracts/shader_params.dart';

/// Base class for 2D escape-time fractals on the complex plane.
///
/// Subclasses define parameter defaults and wire them to shader uniforms in
/// [configureShader]. Pipeline-emitted modules follow the template in
/// `scripts/research/admit/templates/dart/escape_time_module.j2`.
abstract class EscapeTimeModule extends PipelineModuleBase {
  const EscapeTimeModule({
    required super.id,
    required super.shader,
  });

  /// Exponent d in z -> z^d + c. Default 2.0 for classic Mandelbrot.
  double get defaultPower => 2.0;

  /// Escape radius |z| > bailout triggers loop termination.
  double get defaultBailout => 2.0;

  /// Max iterations per pixel.
  int get defaultIterations => 500;

  /// Deep-zoom rendering strategy. Override for perturbation-capable fractals.
  DeepZoomStrategy get deepZoom => DeepZoomStrategy.none;
}

// Base class for strange attractors (Lorenz, Rössler, Chen, Lü, etc.).
import '../pipeline_contracts/pipeline_module_base.dart';

abstract class AttractorModule extends PipelineModuleBase {
  const AttractorModule({
    required super.id,
    required super.shader,
  });

  int get defaultIterations => 100000;
  double get defaultStepSize => 0.01;
}

// Base class for cellular automaton / stochastic fractals.
import '../pipeline_contracts/pipeline_module_base.dart';

abstract class CellularModule extends PipelineModuleBase {
  const CellularModule({
    required super.id,
    required super.shader,
  });

  int get defaultGenerations => 100;
}

// Base class for Iterated Function Systems (Barnsley fern, Sierpinski, Cantor).
import '../pipeline_contracts/pipeline_module_base.dart';

abstract class IFSModule extends PipelineModuleBase {
  const IFSModule({
    required super.id,
    required super.shader,
  });

  int get defaultIterations => 50000;
}

// Base class for L-System / space-filling fractals (Hilbert, Koch, dragon).
import '../pipeline_contracts/pipeline_module_base.dart';

abstract class LSystemModule extends PipelineModuleBase {
  const LSystemModule({
    required super.id,
    required super.shader,
  });

  int get defaultDepth => 6;
}

// Base class for 3D raymarched fractals (Mandelbulb, IFS 3D, hypercomplex).
import '../pipeline_contracts/pipeline_module_base.dart';

abstract class Raymarched3DModule extends PipelineModuleBase {
  const Raymarched3DModule({
    required super.id,
    required super.shader,
  });

  double get defaultPower => 8.0; // mandelbulb classic
  int get defaultSteps => 120;
  int get defaultIterations => 10;
}
